import React, { useState } from 'react';
import './index.css';
import { ControlPanel } from './components/ControlPanel';
import { CardDisplay } from './components/CardDisplay';
import { FractalMethod, FractalConfig, FractalResponse } from './shared/types';
import { generateFractal } from './services/api';

const CARD_WIDTH = 750; // 2.5 inches * 300 dpi
const CARD_HEIGHT = 1050; // 3.5 inches * 300 dpi

function App() {
    const [selectedMethod, setSelectedMethod] = useState<FractalMethod>(FractalMethod.Mandelbrot);
    const [imageSrc, setImageSrc] = useState<string | undefined>(undefined);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | undefined>(undefined);

    const handleGenerate = async (method?: FractalMethod) => {
        setLoading(true);
        setError(undefined);

        const methodToUse = method || selectedMethod;
        if (method) setSelectedMethod(method);

        const config: FractalConfig = {
            method: methodToUse,
            width: CARD_WIDTH,
            height: CARD_HEIGHT,
            seed: Math.floor(Math.random() * 1000000),
        };

        try {
            const response = await generateFractal(config);
            if (response.success && (response as FractalResponse).imageBase64) {
                setImageSrc((response as FractalResponse).imageBase64);
            } else {
                setError((response as any).error || 'Failed to generate image');
            }
        } catch (err) {
            setError('An unexpected error occurred.');
        } finally {
            setLoading(false);
        }
    };

    const handleSurpriseMe = () => {
        const methods = Object.values(FractalMethod);
        const randomMethod = methods[Math.floor(Math.random() * methods.length)];
        handleGenerate(randomMethod);
    };

    return (
        <div className="app-container">
            <header className="app-header">
                <h1>Fractal Card Generator</h1>
            </header>
            <main className="main-content">
                <section className="controls-section">
                    <ControlPanel
                        selectedMethod={selectedMethod}
                        onMethodChange={setSelectedMethod}
                        onGenerate={() => handleGenerate()}
                        onSurpriseMe={handleSurpriseMe}
                        isGenerating={loading}
                    />
                </section>
                <section className="display-section">
                    <CardDisplay imageSrc={imageSrc} isLoading={loading} error={error} />
                </section>
            </main>
        </div>
    );
}

export default App;
